INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('e5bc2cfc-b3f2-5b78-95d7-3d1b18eee6ef', 'education-islamique-2eme', 'سورة الهمزة وسورة العصر', 'نتعلّم سورة الهمزة وسورة العصر، ونعرف قيمة الوقت والعمل الصالح، ونحبّ الإحسان إلى الوالدين والنظافة', '# 📖 سورة الهمزة وسورة العصر — الوقت والأخلاق

> 💡 «نتعلّم سورتين قصيرتين، وننهى عن السخرية، ونحبّ الوقت والعمل الصالح.»

## 🌟 سورة الهمزة

**سورة الهمزة** سورةٌ من القرآن الكريم، عدد آياتها **تسع** آيات. تذمّ السورة من يسخر من الناس ويعيبهم، ومن يجمع المال ولا يعطي منه. نقرأ منها أوّل آيةٍ:

وَيْلٌ لِكُلِّ هُمَزَةٍ لُمَزَةٍ

ومعناها: العذاب لمن يسخر من الناس ويعيبهم. فنتعلّم ألّا نسخر من أحدٍ، وأن نحبّ الخير للناس.

## ⏳ سورة العصر

**سورة العصر** سورةٌ قصيرةٌ من القرآن الكريم، عدد آياتها **ثلاث** آيات. نقرؤها كاملةً:

وَالْعَصْرِ

إِنَّ الْإِنْسَانَ لَفِي خُسْرٍ

إِلَّا الَّذِينَ آمَنُوا وَعَمِلُوا الصَّالِحَاتِ وَتَوَاصَوْا بِالْحَقِّ وَتَوَاصَوْا بِالصَّبْرِ

تُعلّمنا أنّ **الوقت** غالٍ، وأنّ الرابح من **آمن** بالله **وعمل الصالحات** (الأعمال الطيّبة) ونصح الناس بالحقّ والصبر.

## 👨‍👩‍👧 الإحسان إلى الوالدين

من أجمل الأعمال **برّ الوالدين**: نطيع أبانا وأمّنا في الخير، ونتكلّم معهما بلطف، ونساعدهما، وندعو لهما. فالله يحبّ من يُحسن إلى والديه.

## 🧼 النظافة من الإيمان

ديننا يحبّ **النظافة**: نغسل أيدينا، ونُنظّف أسناننا، ونلبس ثيابًا نظيفة، ونحافظ على نظافة بيتنا ومدرستنا. **النظافة** عملٌ صالحٌ جميل يحبّه الله.

> 🗝️ تذكّر: سورة العصر **3** آيات، وسورة الهمزة **9** آيات.

## ✨ نجمع الخير

نتعلّم من هذا الفصل أن نحفظ **وقتنا** في الخير، ونعمل **الصالحات**، ونبرّ **والدينا**، ونحبّ **النظافة**، وألّا نسخر من أحد. هكذا نكون من الرابحين.

> 🏆 أحسنت! حفظتَ سورتين وتعلّمتَ أخلاقًا جميلة. في الفصل القادم نتعلّم سورة التكاثر وسورة القارعة وآداب الاستئذان.', '# 📜 ملخّص: سورة الهمزة وسورة العصر

- **سورة الهمزة**: 9 آيات، تنهى عن السخرية من الناس وعن جمع المال دون عطاء.
- **سورة العصر**: 3 آيات، تُعلّمنا أنّ الوقت غالٍ.
- **الرابح في العصر**: من آمن وعمل الصالحات وتواصى بالحقّ والصبر.
- **برّ الوالدين**: نطيع أبانا وأمّنا في الخير ونتكلّم بلطف ونساعدهما وندعو لهما.
- **النظافة**: نغسل أيدينا وننظّف أسناننا وثيابنا وبيتنا ومدرستنا.
- **العبرة**: نحفظ وقتنا في الخير، ونعمل الصالحات، ولا نسخر من أحد.', 3)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('790faaf6-8269-5d63-892b-75894e89084b', 'education-islamique-2eme', 'سورة التكاثر وسورة القارعة', 'نتعلّم سورة التكاثر وسورة القارعة، ونعرف يوم الحساب وثقل الأعمال الصالحة، ونتعلّم آداب الاستئذان', '# 📖 سورة التكاثر وسورة القارعة — يوم الحساب

> 💡 «نتعلّم أنّ الأعمال الصالحة تثقُل ميزاننا يوم القيامة، وأنّ الاستئذان أدبٌ جميل.»

## 🌟 سورة التكاثر

**سورة التكاثر** سورةٌ من القرآن الكريم، عدد آياتها **ثمانٍ**. تُعلّمنا ألّا ننشغل بكثرة المال والأشياء عن طاعة الله والعمل الصالح. نقرأ منها أوّل آيةٍ:

أَلْهَاكُمُ التَّكَاثُرُ

ومعناها: شغلكم التفاخر بكثرة الأموال والأولاد عن ذكر الله. فنتعلّم أن نهتمّ بالخير والآخرة، لا بالتفاخر.

## ⚖️ سورة القارعة

**سورة القارعة** سورةٌ من القرآن الكريم، عدد آياتها **إحدى عشرة** آية. «القارعة» اسمٌ من أسماء **يوم القيامة**. نقرأ منها أوّل ثلاث آيات:

الْقَارِعَةُ

مَا الْقَارِعَةُ

وَمَا أَدْرَاكَ مَا الْقَارِعَةُ

تُعلّمنا السورة أنّ في يوم القيامة **ميزانًا**: من ثقُلت أعماله الصالحة فاز بالجنّة. فنُكثر من **الأعمال الصالحة** لتثقُل في ميزاننا.

## 🚪 آداب الاستئذان

من الأدب الجميل **الاستئذان**: قبل أن ندخل بيتًا أو غرفةً، **نستأذن** ونطرق الباب ونُسلّم. نقول: «السلام عليكم، هل أدخل؟»، وننتظر الإذن. فإن قيل لنا «ارجع» رجعنا بلا غضب. الاستئذان يحفظ حقّ الناس ويُسعدهم.

> 🗝️ تذكّر: سورة التكاثر **8** آيات، وسورة القارعة **11** آية.

## ✨ نعمل الصالحات

نتعلّم من هذا الفصل ألّا ننشغل بالتفاخر، وأن نُكثر من **الأعمال الصالحة** لتثقُل ميزاننا يوم القيامة، وأن نستأذن قبل الدخول أدبًا واحترامًا للناس.

> 🏆 أحسنت! حفظتَ سورتين وتعلّمتَ أدب الاستئذان. في الفصل القادم نتعلّم سورة العاديات وآداب الأكل.', '# 📜 ملخّص: سورة التكاثر وسورة القارعة

- **سورة التكاثر**: 8 آيات، تنهى عن الانشغال بكثرة المال والتفاخر عن طاعة الله.
- **أوّل آية**: ألهاكم التكاثر.
- **سورة القارعة**: 11 آية، و«القارعة» اسمٌ من أسماء يوم القيامة.
- **الميزان**: يوم القيامة تُوزن الأعمال؛ من ثقُلت حسناته فاز بالجنّة.
- **آداب الاستئذان**: نطرق الباب ونُسلّم ونقول «هل أدخل؟» وننتظر الإذن.
- **العبرة**: نُكثر من الأعمال الصالحة، ونستأذن قبل الدخول أدبًا.', 4)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('3f16f53b-eafa-5e3c-8502-1bbb15f10da0', 'education-islamique-2eme', 'سورة العاديات وآداب الأكل', 'نتعلّم سورة العاديات، ونشكر الله على نعمه، ونتعلّم آداب الأكل: التسمية والأكل باليمين والشكر', '# 📖 سورة العاديات وآداب الأكل — نشكر الله

> 💡 «نشكر الله على نعمه الكثيرة، ونأكل بأدبٍ كما علّمنا نبيّنا ﷺ.»

## 🌟 سورة العاديات

**سورة العاديات** سورةٌ من القرآن الكريم، عدد آياتها **إحدى عشرة** آية. تبدأ بذكر **الخيل** التي تجري في سبيل الله، ثمّ تذكّر الإنسان أن يشكر ربّه ولا يجحد نعمه. نقرأ منها أوّل آيتين:

وَالْعَادِيَاتِ ضَبْحًا

فَالْمُورِيَاتِ قَدْحًا

تُعلّمنا السورة أن **نشكر الله** على نعمه، وألّا نكون من الذين ينسون فضل ربّهم.

## 🤲 نعم الله كثيرة

أنعم الله علينا بنعمٍ كثيرة: **الصحّة**، و**الطعام**، و**الوالدان**، و**الماء**، و**العقل**. فعلينا أن **نحمد الله** ونشكره على نعمه، ونستعملها في الخير.

## 🍽️ آداب الأكل

علّمنا نبيّنا ﷺ آدابًا جميلة عند الأكل:

| الأدب | كيف نفعله |
| --- | --- |
| **التسمية** | نقول «بسم الله» قبل أن نأكل |
| **اليمين** | نأكل بيدنا اليمنى |
| **القرب** | نأكل ممّا أمامنا |
| **الشكر** | نقول «الحمد لله» بعد الأكل |
| **عدم الإسراف** | لا نأخذ أكثر ممّا نحتاج ولا نرمي الطعام |

## 🧼 نظافة عند الأكل

قبل الأكل **نغسل أيدينا**، ونجلس بأدب، ونأكل بهدوءٍ دون عبثٍ بالطعام. هكذا يكون أكلنا نظيفًا جميلًا.

> 🗝️ تذكّر: قبل الأكل نقول **بسم الله**، وبعده **الحمد لله**.

## ✨ نشكر المُنعم

نتعلّم من هذا الفصل أن **نشكر الله** على نعمه، وأن نأكل بأدبٍ: بالتسمية واليمين والشكر، وألّا نُسرف. فالشكر يزيد النعمة ويُرضي الله.

> 🏆 أحسنت! تعلّمتَ شكر النعم وآداب الأكل. في الفصل القادم نتعلّم سورة الزلزلة ونعرف نعم الله والإخلاص في العمل.', '# 📜 ملخّص: سورة العاديات وآداب الأكل

- **سورة العاديات**: 11 آية، تبدأ بذكر الخيل، وتذكّر الإنسان بشكر ربّه.
- **أوّل آية**: والعاديات ضبحًا.
- **نعم الله**: الصحّة والطعام والوالدان والماء والعقل، فنشكره عليها.
- **آداب الأكل**: نقول «بسم الله» قبله، ونأكل باليمين وممّا أمامنا.
- **بعد الأكل**: نقول «الحمد لله» شكرًا لله.
- **عدم الإسراف**: لا نأخذ أكثر ممّا نحتاج ولا نرمي الطعام.
- **النظافة**: نغسل أيدينا ونأكل بهدوءٍ وأدب.', 5)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('c063fb6b-5ae5-5cfb-9d51-9f1ddacc4fb1', 'education-islamique-2eme', 'سورة الزلزلة ونعم الله', 'نتعلّم سورة الزلزلة ونعرف أنّ الله يرى كلّ أعمالنا، ونتبيّن نعم الله، ونتعلّم الإخلاص في العمل', '# 📖 سورة الزلزلة ونعم الله — الله يرى كلّ شيء

> 💡 «الله يرى كلّ أعمالنا، ولو كانت صغيرةً مثل الذرّة، فنُخلص في عملنا.»

## 🌟 سورة الزلزلة

**سورة الزلزلة** سورةٌ من القرآن الكريم، عدد آياتها **ثمانٍ**. تُحدّثنا عن يوم القيامة حين **تزلزل الأرض**، وتُعلّمنا أنّ **كلّ عملٍ** صغيرٍ أو كبير سنراه. نقرأ آخر آيتين منها:

فَمَنْ يَعْمَلْ مِثْقَالَ ذَرَّةٍ خَيْرًا يَرَهُ

وَمَنْ يَعْمَلْ مِثْقَالَ ذَرَّةٍ شَرًّا يَرَهُ

ومعناها: من عمل خيرًا قليلًا (مثل وزن ذرّة) رآه، ومن عمل شرًّا قليلًا رآه. فلا عمل يضيع عند الله.

## 👀 الله يرى أعمالنا

نتعلّم أنّ **الله يرى** كلّ ما نفعل، في السرّ والعلن. فإذا فعلنا خيرًا صغيرًا كافأنا الله، وإذا فعلنا سوءًا صغيرًا حاسبنا. لذلك نحرص على **الخير** دائمًا، حتّى لو كان صغيرًا.

## 🎁 نعم الله علينا

أنعم الله علينا بنعمٍ لا تُعدّ. قال الله في سورة البقرة:

هُوَ الَّذِي خَلَقَ لَكُمْ مَا فِي الْأَرْضِ جَمِيعًا

أي خلق لنا كلّ ما في الأرض: **الماء**، و**النبات**، و**الحيوان**، و**الشمس**، و**الهواء**. فكلّ هذه نعمٌ نشكر الله عليها.

## 💎 الإخلاص في العمل

**الإخلاص** أن نعمل العمل لله وحده، ونُتقنه، سواءٌ رآنا أحدٌ أو لم يرنا. فالتلميذ المخلص يجتهد في درسه حتّى لو غاب المعلّم، لأنّه يعلم أنّ **الله يراه**. الإخلاص يجعل عملنا جميلًا مقبولًا.

> 🗝️ تذكّر: من يعمل **مثقال ذرّةٍ** خيرًا يره، ومن يعمل مثقال ذرّةٍ شرًّا يره.

## ✨ نعمل الخير بإخلاص

نتعلّم من هذا الفصل أنّ **الله يرى** كلّ أعمالنا، وأنّ نعمه كثيرة نشكرها، وأن نعمل بـ**إخلاص** لله، فنُتقن عملنا ونحرص على الخير ولو كان صغيرًا.

> 🏆 أحسنت! عرفتَ أنّ الله يرى كلّ شيء. في الفصل القادم نتعلّم سورة العلق، أوّل ما نزل من القرآن.', '# 📜 ملخّص: سورة الزلزلة ونعم الله

- **سورة الزلزلة**: 8 آيات، تُحدّثنا عن يوم القيامة حين تزلزل الأرض.
- **القاعدة الكبرى**: من يعمل مثقال ذرّةٍ خيرًا يره، ومن يعمل مثقال ذرّةٍ شرًّا يره.
- **الله يرى**: كلّ أعمالنا في السرّ والعلن، فلا عمل يضيع عنده.
- **نعم الله**: خلق لنا ما في الأرض (الماء والنبات والحيوان والشمس)، فنشكره.
- **الإخلاص**: أن نعمل لله ونُتقن عملنا، رآنا أحدٌ أم لم يرنا.
- **العبرة**: نحرص على الخير ولو كان صغيرًا، ونعمل بإخلاصٍ لله.', 6)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('2475e4eb-40ca-5735-bcfb-52682fb60ee7', 'education-islamique-2eme', 'سورة العلق', 'نتعلّم سورة العلق، أوّل ما نزل من القرآن، ونعرف فضل العلم والقراءة والقلم، وأنّ الله علّم الإنسان', '# 📖 سورة العلق — اقرأ باسم ربّك

> 💡 «أوّل ما نزل من القرآن كلمة (اقرأ)، فما أجمل العلم والقراءة!»

## 🌟 سورة العلق

**سورة العلق** سورةٌ من القرآن الكريم، عدد آياتها **تسع عشرة** آية. وهي **أوّل ما نزل** من القرآن الكريم على نبيّنا **محمّد ﷺ**. أوّل كلمةٍ فيها هي **اقرأ**، فالقرآن يدعونا إلى **العلم** و**القراءة**.

## 🕌 نقرأ أوّل الآيات

نبدأ بالبسملة، ثمّ نقرأ أوّل خمس آياتٍ من السورة:

اقْرَأْ بِاسْمِ رَبِّكَ الَّذِي خَلَقَ

خَلَقَ الْإِنْسَانَ مِنْ عَلَقٍ

اقْرَأْ وَرَبُّكَ الْأَكْرَمُ

الَّذِي عَلَّمَ بِالْقَلَمِ

عَلَّمَ الْإِنْسَانَ مَا لَمْ يَعْلَمْ

## 🤲 ماذا تعني السورة؟

تأمرنا السورة أن **نقرأ** ونتعلّم، ونبدأ **باسم ربّنا** الذي خلقنا. وتُخبرنا أنّ الله هو الذي **علّم الإنسان** بالقلم والكتابة، وعلّمه ما لم يكن يعرف. فالعلم نعمةٌ من الله نشكره عليها.

## ✏️ فضل العلم والقلم

ذكر الله **القلم** في السورة، لأنّ به نكتب ونتعلّم. فنحبّ **القراءة** و**الكتابة**، ونجتهد في **مدرستنا**، ونحترم **معلّمينا** و**كتبنا**. العلم نورٌ يرفع صاحبه.

> 🗝️ تذكّر: أوّل كلمةٍ نزلت من القرآن هي **اقرأ**، وسورة العلق **19** آية.

## ✨ نطلب العلم

نتعلّم من سورة العلق أن **نقرأ** ونتعلّم باسم الله، وأن نشكر الله الذي **علّمنا**، ونجتهد في طلب العلم، فالعلم خيرٌ كثير يحبّه الله.

> 🏆 أحسنت! عرفتَ أوّل ما نزل من القرآن وفضل العلم. في الفصل القادم نتعلّم سورة القدر والتعاون والتعايش السلمي.', '# 📜 ملخّص: سورة العلق

- **سورة العلق**: 19 آية، وهي أوّل ما نزل من القرآن الكريم على نبيّنا ﷺ.
- **أوّل كلمة**: اقرأ، فالقرآن يدعونا إلى العلم والقراءة.
- **أوّل آية**: اقرأ باسم ربّك الذي خلق.
- **الله علّم الإنسان**: بالقلم، وعلّمه ما لم يكن يعرف.
- **فضل القلم**: به نكتب ونتعلّم، فنحبّ القراءة والكتابة.
- **العبرة**: نطلب العلم ونجتهد في مدرستنا ونشكر الله الذي علّمنا.', 7)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('1b2a8fb4-f811-5d00-9a53-7bfb4948d31e', 'education-islamique-2eme', 'التعاون والتعايش السلمي وسورة القدر', 'نتعلّم سورة القدر، ونحبّ التعاون والتعايش السلمي مع الناس، ونحفظ حديثين شريفين عن العون ومحبّة الخير', '# 📖 التعاون والتعايش السلمي وسورة القدر

> 💡 «نتعاون ونعيش بسلامٍ مع الناس، ونحبّ لهم ما نحبّ لأنفسنا.»

## 🌟 سورة القدر

**سورة القدر** سورةٌ من القرآن الكريم، عدد آياتها **خمس**. تُحدّثنا عن **ليلة القدر**، وهي ليلةٌ مباركةٌ في رمضان، أُنزل فيها القرآن، وهي خيرٌ من ألف شهر. نقرؤها كاملةً:

إِنَّا أَنْزَلْنَاهُ فِي لَيْلَةِ الْقَدْرِ

وَمَا أَدْرَاكَ مَا لَيْلَةُ الْقَدْرِ

لَيْلَةُ الْقَدْرِ خَيْرٌ مِنْ أَلْفِ شَهْرٍ

تَنَزَّلُ الْمَلَائِكَةُ وَالرُّوحُ فِيهَا بِإِذْنِ رَبِّهِمْ مِنْ كُلِّ أَمْرٍ

سَلَامٌ هِيَ حَتَّى مَطْلَعِ الْفَجْرِ

## 🤝 التعاون

**التعاون** أن يساعد بعضنا بعضًا في الخير. فنساعد أصدقاءنا، ونعين والدينا، ونعمل معًا في تنظيف صفّنا. قال نبيّنا ﷺ:

«وَاللَّهُ فِي عَوْنِ الْعَبْدِ مَا دَامَ الْعَبْدُ فِي عَوْنِ أَخِيهِ»

أي أنّ الله يساعد من يساعد إخوانه. فما أجمل أن نتعاون على الخير!

## 🕊️ التعايش السلمي

**التعايش السلمي** أن نعيش مع الناس بسلامٍ ومحبّة، فلا نؤذي أحدًا، ونحترم الجميع. قال الله:

وَأَحْسِنُوا إِنَّ اللَّهَ يُحِبُّ الْمُحْسِنِينَ

وقال نبيّنا ﷺ:

«لَا يُؤْمِنُ أَحَدُكُمْ حَتَّى يُحِبَّ لِأَخِيهِ مَا يُحِبُّ لِنَفْسِهِ»

أي نحبّ للناس الخير الذي نحبّه لأنفسنا.

> 🗝️ تذكّر: سورة القدر **5** آيات، وليلة القدر **خيرٌ من ألف شهر**.

## ✨ نحبّ الخير للناس

نتعلّم من هذا الفصل أن **نتعاون** على الخير، وأن **نعيش بسلامٍ** مع الناس، وأن **نُحسن** إليهم، ونحبّ لهم ما نحبّ لأنفسنا. بذلك يحبّنا الله ويحبّنا الناس.

> 🏆 أحسنت! أتممتَ رحلتك في التربية الإسلامية لهذه السنة. حفظتَ سورًا جميلة وتعلّمتَ أخلاقًا عظيمة. واصل العمل بها دائمًا!', '# 📜 ملخّص: التعاون والتعايش السلمي وسورة القدر

- **سورة القدر**: 5 آيات، عن ليلة القدر المباركة في رمضان، وهي خيرٌ من ألف شهر.
- **التعاون**: أن يساعد بعضنا بعضًا في الخير.
- **حديث التعاون**: «والله في عون العبد ما دام العبد في عون أخيه».
- **التعايش السلمي**: أن نعيش مع الناس بسلامٍ ومحبّة ولا نؤذي أحدًا.
- **آية الإحسان**: وأحسنوا إنّ الله يحبّ المحسنين.
- **حديث المحبّة**: «لا يؤمن أحدكم حتّى يحبّ لأخيه ما يحبّ لنفسه».
- **العبرة**: نتعاون على الخير، ونحبّ للناس ما نحبّ لأنفسنا.', 8)
