INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('be252d90-1e57-56e1-b7da-7e315c605730', '81a8340f-e70c-51f9-9498-c5a1abc35069', 'ماذا أُنزل في ليلة القدر؟', '[{"id":"a","text":"القرآن الكريم"},{"id":"b","text":"المطر"},{"id":"c","text":"الطعام"},{"id":"d","text":"لا شيء"}]'::jsonb, 'a', 'أُنزل القرآن الكريم في ليلة القدر: إنّا أنزلناه في ليلة القدر، فهي ليلةٌ عظيمةٌ مباركة.', 1)
