INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b7c8c7fd-446c-557f-a627-28fdea407770', '81a8340f-e70c-51f9-9498-c5a1abc35069', 'صديقان: واحدٌ يساعد زملاءه دائمًا، وآخر يرفض. من ينطبق عليه «الله في عونه»؟', '[{"id":"a","text":"من يرفض المساعدة"},{"id":"b","text":"من يساعد زملاءه"},{"id":"c","text":"لا أحد"},{"id":"d","text":"كلاهما يرفض"}]'::jsonb, 'b', 'من يساعد زملاءه، فالحديث: والله في عون العبد ما دام العبد في عون أخيه. الخطأ الشائع أن نظنّ المساعدة نقصًا، وهي بابٌ لعون الله.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('705ced3f-0a9b-5ec1-bb1a-50e7981abb28', '81a8340f-e70c-51f9-9498-c5a1abc35069', 'كيف نطبّق التعايش السلمي مع جارٍ يختلف عنّا؟', '[{"id":"a","text":"نؤذيه"},{"id":"b","text":"نتجاهله"},{"id":"c","text":"نحترمه ونعيش معه بسلامٍ ونُحسن إليه"},{"id":"d","text":"نتشاجر معه"}]'::jsonb, 'c', 'نحترمه ونعيش معه بسلامٍ ونُحسن إليه، فالتعايش السلمي يشمل كلّ الناس، والله يحبّ المحسنين.', 3)
