  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('83dec037-bf7c-5e52-a050-82964dc40b3d', '81a8340f-e70c-51f9-9498-c5a1abc35069', 'لماذا قال نبيّنا ﷺ «لا يؤمن أحدكم حتّى يحبّ لأخيه ما يحبّ لنفسه»؟', '[{"id":"a","text":"ليأمرنا بالأنانية"},{"id":"b","text":"ليأمرنا بالشجار"},{"id":"c","text":"بلا معنى"},{"id":"d","text":"ليبيّن أنّ محبّة الخير للناس من كمال الإيمان"}]'::jsonb, 'd', 'ليبيّن أنّ محبّة الخير للناس من كمال الإيمان، فالمؤمن يفرح لإخوانه بما يفرح به لنفسه.', 4)
ON CONFLICT (id) DO UPDATE SET
