  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7e1e08b0-e12a-579f-8c65-c6910768c1bd', '81a8340f-e70c-51f9-9498-c5a1abc35069', 'كيف نجمع بين العبادة في ليلة القدر وحبّ الخير للناس؟', '[{"id":"a","text":"نعبد الله ونُحسن إلى الناس ونتعاون معهم"},{"id":"b","text":"نعبد ونؤذي الناس"},{"id":"c","text":"نترك العبادة"},{"id":"d","text":"نهمل الناس"}]'::jsonb, 'a', 'نجمع بينهما بأن نعبد الله ونُحسن إلى الناس ونتعاون معهم، فالدين عبادةٌ لله وإحسانٌ للخلق.', 5)
